proof fn phi_3_advancement_equals_log_area_len_wraps_to_same(info: LogInfo, state: AbstractLogState)
    requires
        info.log_area_len >= MIN_LOG_AREA_SIZE,
        info.log_length <= info.log_plus_pending_length <= info.log_area_len,
        info.head_log_area_offset == info.head as int % info.log_area_len as int,
        info.log_length as u128 == info.log_area_len as u128,
        info.head <= info.head + info.log_area_len as u128,
    ensures
        (info.head + info.log_area_len as u128) as int % info.log_area_len as int == info.head_log_area_offset as int,
{
    lemma_mod_multiples_vanish(1, info.head as int % info.log_area_len as int, info.log_area_len as int);
    lemma_fundamental_div_mod(info.head as int, info.log_area_len as int);
    lemma_mod_multiples_vanish(info.head as int / info.log_area_len as int + 1, 0, info.log_area_len as int);
}

